import { glossaryEnrichment } from './glossaryEnrichment.js';

const definition = (group, number) => `/definitions/${group}/${number}`;

const t = (id, term, aliases, short, child, analogy, example, notThis, topicId, definitionLink = null) => ({
  id,
  term,
  aliases,
  short,
  child,
  analogy,
  example,
  notThis,
  topicId,
  definitionLink,
});

const glossaryBase = [
  // Язык математики и кольца
  t('set', 'Множество', ['множества', 'множеству', 'множеством'], 'Набор объектов, которые мы решили рассматривать вместе.', 'Представь коробку с игрушками. Коробка — это множество, а каждая игрушка внутри — элемент. Игрушки могут быть совсем разными; важно только ясно понимать, что лежит в коробке, а что нет.', 'Коробка с выбранными предметами.', 'Множество {1, 2, 3} содержит три числа.', 'Множество не обязано быть упорядоченным списком: {1,2} и {2,1} — одно множество.', 'rings-fields'),
  t('element', 'Элемент', ['элемента', 'элементу', 'элементом', 'элементы'], 'Один объект, входящий в множество.', 'Если множество — коробка, элемент — одна конкретная вещь из неё. Буквой a часто называют предмет, а буквой A — всю коробку.', 'Одна игрушка из коробки.', 'Число 2 — элемент множества {1,2,3}.', 'Элемент и множество — разные уровни: число 2 не равно множеству {2}.', 'rings-fields'),
  t('belongs', 'Принадлежит', ['принадлежит множеству', 'принадлежности', 'входит в', '∈'], 'Знак ∈ сообщает, что объект находится в данном множестве.', 'Запись a∈A читается: «a лежит в коробке A». Перечёркнутый знак a∉A означает, что такого предмета в коробке нет.', 'Наклейка «есть внутри».', '2∈{1,2,3}, но 5∉{1,2,3}.', 'Не путай ∈ с ⊂: элемент лежит в множестве, а подмножество целиком содержится в другом множестве.', 'rings-fields'),
  t('operation', 'Операция', ['операции', 'операцией', 'бинарная операция'], 'Правило, которое берёт объекты и выдаёт новый объект.', 'Операция похожа на машинку: кладём в неё два допустимых предмета, например a и b, а она по фиксированному правилу выдаёт результат a*b. Замкнутость означает, что результат снова из нашей коробки.', 'Кухонный прибор с понятным рецептом.', 'Сложение целых чисел: 3+5=8.', 'Операция — не случайный ответ: для одинаковых входов результат всегда один и тот же.', 'rings-fields'),
  t('rule', 'Правило', ['правила', 'правилом'], 'Однозначная инструкция, что сделать с входными данными.', 'Это договорённость вроде «каждому числу прибавь один». Мы обязаны применять её одинаково ко всем допустимым входам.', 'Рецепт, который нельзя менять по ходу.', 'Правило f(x)=x+1 отправляет 3 в 4.', 'Фраза «сделай как-нибудь» не является математическим правилом.', 'rings-fields'),
  t('environment', 'Математическая среда', ['среда', 'среде', 'среды'], 'Объекты и правила работы с ними, принятые в текущей задаче.', 'Это как игровая площадка со своими предметами и законами. В среде целых чисел можно складывать и умножать, но число 1/2 уже не живёт внутри неё. Перед вычислениями всегда уточняют, где мы работаем.', 'Игра вместе с её полем и правилами.', 'В кольце Z/5Z числа считаются по модулю 5, поэтому 3+4=2.', '«Среда» здесь — поясняющее слово, а не отдельный строгий объект из официальной программы.', 'rings-fields'),
  t('number', 'Число', ['числа', 'числом', 'чисел'], 'Объект, которым считают, измеряют или задают коэффициент.', 'Числа бывают разных видов: целые, дробные, вещественные, комплексные. В алгебре важно не только значение числа, но и в какой системе оно живёт.', 'Разные виды измерительных жетонов.', '−2∈Z, 1/2∈Q, i∈C.', 'Не каждое число допустимо в каждом поле: i не является вещественным числом.', 'rings-fields'),
  t('zero', 'Ноль', ['нуля', 'нулю', 'нулём', 'нулевой элемент', '0'], 'Нейтральный элемент сложения: a+0=a.', 'Ноль — элемент, добавление которого ничего не меняет. В векторном пространстве есть нулевой вектор с той же ролью.', 'Пустая добавка.', '7+0=7, v+0=v.', 'Ноль не всегда записывается одной цифрой: нулевая матрица состоит из многих нулей.', 'rings-fields'),
  t('one', 'Единица', ['единицы', 'единицей', 'единичный элемент', '1'], 'Нейтральный элемент умножения: a·1=1·a=a.', 'Единица — элемент, умножение на который ничего не меняет. В матрицах такую роль играет единичная матрица I.', 'Прозрачный множитель.', '9·1=9, AI=A.', 'Единица кольца не обязана выглядеть как обычное число 1.', 'rings-fields'),
  t('addition', 'Сложение', ['сложения', 'сложению', 'складывать', 'суммирование'], 'Операция, объединяющая два элемента в их сумму.', 'Сложение говорит, как собрать два объекта одного вида в третий. Для векторов мы складываем соответствующие координаты.', 'Соединить содержимое двух корзинок.', '(1,2)+(3,4)=(4,6).', 'Сложение в абстрактной группе не обязано быть обычной школьной арифметикой.', 'rings-fields'),
  t('multiplication', 'Умножение', ['умножения', 'умножению', 'умножать', 'произведение'], 'Операция, сопоставляющая двум элементам их произведение.', 'Это второе правило соединения объектов. В разных средах оно разное: числа перемножают, матрицы составляют как преобразования, многочлены раскрывают по коэффициентам.', 'Сцепить два действия одно за другим.', 'В Z: 2·3=6; для матриц обычно AB≠BA.', 'Умножение не обязано быть коммутативным.', 'rings-fields'),
  t('inverse-element', 'Обратный элемент', ['обратного элемента', 'обратным элементом', 'мультипликативная обратная', 'a⁻¹'], 'Элемент, который при умножении с данным даёт единицу.', 'Обратный элемент отменяет умножение: если a сначала изменило объект, a⁻¹ возвращает его назад. Он существует не у каждого элемента и никогда не существует у нуля в поле.', 'Кнопка «отменить».', 'Для 2 в Q обратный равен 1/2, потому что 2·(1/2)=1.', 'Противоположный −a отменяет сложение, а обратный a⁻¹ — умножение.', 'rings-fields'),
  t('group', 'Группа', ['группы', 'группой'], 'Множество с ассоциативной операцией, единицей и обратными элементами.', 'В группе действия можно соединять, есть действие «ничего не делать», и каждое действие можно отменить. Порядок действий иногда важен.', 'Набор движений с кнопкой отмены.', 'Целые числа образуют группу по сложению.', 'Группа имеет одну главную операцию; кольцо — более богатая структура с двумя.', 'rings-fields'),
  t('abelian-group', 'Абелева группа', ['абелевой группы', 'коммутативная группа'], 'Группа, в которой порядок выполнения операции не влияет на результат.', 'Это группа, где a*b и b*a всегда одинаковы. Для сложения в кольце именно это обязательно.', 'Два независимых дела, которые можно выполнить в любом порядке.', '(Z,+) — абелева группа.', 'Не всякая группа абелева: перестановки или повороты могут зависеть от порядка.', 'rings-fields'),
  t('associativity', 'Ассоциативность', ['ассоциативности', 'ассоциативно', 'ассоциативная'], 'Скобки можно переставить: (ab)c=a(bc).', 'Если соединяем три действия, можно сначала объединить первые два или последние два — итог тот же. Порядок самих элементов при этом не меняется.', 'Упаковать три одинаково совместимых коробки двумя способами.', '(2·3)·4=2·(3·4).', 'Ассоциативность не разрешает менять a и b местами — это коммутативность.', 'rings-fields'),
  t('commutativity', 'Коммутативность', ['коммутативности', 'коммутативно', 'коммутативная'], 'Множители или слагаемые можно менять местами: ab=ba.', 'Результат не зависит от того, какой из двух объектов поставили первым.', 'Надеть носок на левую и правую ногу в любом порядке.', '2+5=5+2.', 'Матрицы обычно не коммутируют: AB может отличаться от BA.', 'rings-fields', definition('definitions-module-3', 2)),
  t('distributivity', 'Дистрибутивность', ['дистрибутивности', 'распределительный закон'], 'Умножение раскрывает сумму: a(b+c)=ab+ac.', 'Если один пакет a действует на сумму двух вещей, можно применить его отдельно к каждой, а результаты сложить.', 'Раздать каждому ребёнку одинаковый набор.', '3(2+4)=3·2+3·4.', 'Это не ассоциативность: здесь связываются две разные операции.', 'rings-fields'),
  t('ring', 'Кольцо', ['кольца', 'кольцу', 'кольцом', 'кольце'], 'Среда, где можно складывать, вычитать и умножать по согласованным правилам.', 'Кольцо — коробка объектов с двумя машинками: сложением и умножением. Сложение всегда можно отменить, умножение ведёт себя аккуратно со скобками и раскрывает суммы, но делить обычно можно не на всё.', 'Арифметическая мастерская без гарантированного деления.', 'Z — кольцо: целые числа замкнуты относительно +, − и ·.', 'Кольцо — не геометрический бублик и не обязательно поле.', 'rings-fields', definition('definitions-module-3', 1)),
  t('field', 'Поле', ['поля', 'полю', 'полем', 'поле скаляров'], 'Коммутативное кольцо, где каждый ненулевой элемент можно делить.', 'Поле — особенно удобное кольцо: кроме сложения, вычитания и умножения здесь можно делить на любой ненулевой элемент. Поэтому в поле хорошо решаются линейные уравнения.', 'Полностью оборудованная арифметическая кухня.', 'Q, R, C и F₅ — поля.', 'Z не поле: у 2 нет обратного целого числа.', 'rings-fields', definition('definitions-module-3', 5)),
  t('zero-divisor', 'Делитель нуля', ['делителя нуля', 'делители нуля', 'нулевой делитель'], 'Ненулевой элемент, который с другим ненулевым элементом даёт ноль.', 'Два непустых предмета внезапно взаимно уничтожаются при умножении. В поле такого быть не может.', 'Две детали, которые вместе исчезают.', 'В Z/6Z классы 2 и 3 ненулевые, но 2·3=0.', 'Сам ноль обычно не называют делителем нуля.', 'rings-fields', definition('definitions-module-3', 3)),
  t('integral-domain', 'Целостное кольцо', ['целостного кольца', 'область целостности'], 'Коммутативное кольцо с единицей и без делителей нуля.', 'Это кольцо, где два ненулевых элемента при умножении никогда не пропадут в ноль. Деление всё ещё может существовать не всегда.', 'Мастерская без взаимного уничтожения деталей.', 'Z — целостное кольцо, но не поле.', 'Целостность слабее свойства поля.', 'rings-fields', definition('definitions-module-3', 4)),
  t('characteristic', 'Характеристика поля', ['характеристики поля', 'char', 'char F'], 'Сколько сложений единицы даёт ноль; если никогда — характеристика 0.', 'Начинаем с нуля и снова прибавляем единицу. Если через p шагов вернулись в ноль, характеристика равна p. Если круг никогда не замыкается, она нулевая.', 'Длина циферблата арифметических часов.', 'В F₅: 1+1+1+1+1=0, поэтому char F₅=5.', 'Нулевая характеристика не означает поле из одного нуля.', 'rings-fields', definition('definitions-module-3', 7)),
  t('ideal', 'Идеал', ['идеала', 'идеалу', 'идеалом'], 'Аддитивная часть кольца, поглощающая умножение на любые элементы кольца.', 'Идеал похож на краску: если элемент уже окрашен, умножение на любой элемент кольца оставляет результат окрашенным. Поэтому весь идеал можно безопасно объявить нулём в факторкольце.', 'Впитывающая область.', '2Z — идеал в Z: любое целое, умноженное на чётное, снова чётно.', 'Подкольцо не обязано быть идеалом.', 'rings-fields', definition('definitions-module-3', 9)),
  t('homomorphism', 'Гомоморфизм', ['гомоморфизма', 'гомоморфизм колец'], 'Отображение, сохраняющее операции структуры.', 'Это переводчик между двумя математическими мирами: сложил или умножил до перевода — получишь то же, что если сначала перевести каждый объект, а потом выполнить действие.', 'Переводчик, сохраняющий смысл действий.', 'Z→Z/5Z, n↦[n], сохраняет + и ·.', 'Любая функция не является гомоморфизмом.', 'rings-fields', definition('definitions-module-3', 10)),
  t('quotient-ring', 'Факторкольцо', ['факторкольца', 'фактор-кольцо', 'R/I'], 'Кольцо, где элементы, отличающиеся на элемент идеала, считаются одинаковыми.', 'Мы склеиваем все числа, разность которых лежит в идеале. Это как часы: 1 и 13 показывают одно и то же положение на циферблате из 12 делений.', 'Арифметические часы со склеенными значениями.', 'Z/5Z состоит из пяти классов остатков.', 'Факторизовать кольцо можно по идеалу, не по произвольному подмножеству.', 'rings-fields'),
  t('algebra-over-field', 'Алгебра над полем', ['алгебры над полем', 'F-алгебра'], 'Векторное пространство над полем, в котором векторы ещё можно согласованно умножать.', 'В обычном векторном пространстве векторы складывают и растягивают. В алгебре им дополнительно разрешили умножаться друг на друга, причём это дружит со скалярами и сложением.', 'Векторная мастерская с дополнительной машинкой умножения.', 'Матрицы Mₙ(R) образуют алгебру над R.', 'Алгебра над полем не обязана быть коммутативной.', 'rings-fields', definition('definitions-exam', 2)),

  // Линейные пространства
  t('vector', 'Вектор', ['вектора', 'вектору', 'вектором', 'векторы'], 'Объект, который можно складывать с такими же и умножать на скаляры.', 'Вектор — стрелка-направление или список характеристик. Главное не картинка, а правила: векторы можно складывать и растягивать числами.', 'Стрелка, которую можно растянуть и сложить с другой.', '(2,−1) — вектор в R².', 'Вектор не всегда геометрическая стрелка: многочлен тоже может быть вектором.', 'vector-spaces'),
  t('scalar', 'Скаляр', ['скаляра', 'скаляром', 'скаляры'], 'Число из поля, которым умножают вектор.', 'Скаляр — ручка масштаба: число 2 растягивает вектор вдвое, −1 разворачивает его, 0 превращает в нулевой.', 'Регулятор длины и направления.', '3(1,2)=(3,6).', 'Скаляр зависит от выбранного поля.', 'vector-spaces'),
  t('vector-space', 'Векторное пространство', ['линейное пространство', 'пространства векторов'], 'Множество векторов, замкнутое относительно сложения и умножения на скаляры.', 'Это мир, где любые разрешённые стрелки можно складывать и растягивать, не выходя наружу. Все обычные арифметические правила согласованы.', 'Комната всех разрешённых направлений.', 'R² над R — векторное пространство.', 'Просто набор точек не обязательно является пространством.', 'vector-spaces', definition('definitions-module-3', 17)),
  t('linear-combination', 'Линейная комбинация', ['линейной комбинации', 'линейные комбинации'], 'Сумма векторов, умноженных на скаляры.', 'Берём несколько строительных стрелок, каждую растягиваем своим числом и складываем. Так строятся все объекты из их оболочки.', 'Рецепт из базовых деталей с коэффициентами.', '2v₁−3v₂ — линейная комбинация v₁ и v₂.', 'Произведения v₁v₂ или постоянные слагаемые сюда не входят.', 'vector-spaces'),
  t('linear-independence', 'Линейная независимость', ['линейно независимы', 'линейной независимости'], 'Ни один вектор системы нельзя собрать из остальных.', 'Каждая стрелка добавляет действительно новое направление. Единственный способ получить ноль их комбинацией — поставить все коэффициенты равными нулю.', 'Набор инструментов без дублей.', '(1,0) и (0,1) независимы.', 'Непараллельность достаточна только для двух векторов в плоскости.', 'vector-spaces'),
  t('span', 'Линейная оболочка', ['линейной оболочки', 'span', 'линейная оболочка системы'], 'Все линейные комбинации выбранных векторов.', 'Это вся территория, до которой можно добраться, растягивая и складывая данные стрелки.', 'Карта всех мест, достижимых разрешёнными шагами.', 'span((1,0)) — ось Ox.', 'Оболочка включает бесконечно много векторов даже при одном ненулевом генераторе.', 'vector-spaces', definition('definitions-module-3', 23)),
  t('basis', 'Базис', ['базиса', 'базису', 'базисом', 'базисные векторы'], 'Независимый набор векторов, из которого единственным образом собирается весь простор.', 'Базис — минимальный комплект строительных направлений без лишних деталей. Любой вектор можно собрать из него ровно одним способом.', 'Набор координатных линеек.', 'e₁=(1,0), e₂=(0,1) — базис R².', 'Порождающий набор с лишним вектором не является базисом.', 'vector-spaces', definition('definitions-module-3', 18)),
  t('coordinates', 'Координаты', ['координат', 'координатами', 'координатный столбец'], 'Коэффициенты разложения вектора по выбранному базису.', 'Координаты — инструкция, сколько взять каждого базисного направления. Сам вектор один, но при смене базиса инструкция меняется.', 'Адрес одного места на разных картах.', 'v=2e₁−e₂ имеет координаты (2,−1) в базисе e.', 'Координаты — не сам вектор и зависят от базиса.', 'vector-spaces'),
  t('column', 'Столбец', ['столбца', 'столбцу', 'столбцом', 'вектор-столбец'], 'Вертикально записанный список чисел.', 'Столбец — удобная упаковка координат сверху вниз. Матрица действует на такой список и выдаёт новый столбец.', 'Вертикальная коробка ячеек.', '(2,3)ᵀ — столбец из двух чисел.', 'Столбец матрицы и строка имеют разную ориентацию.', 'vector-spaces'),
  t('matrix', 'Матрица', ['матрицы', 'матрице', 'матрицей', 'матричный'], 'Прямоугольная таблица чисел, кодирующая линейное правило или форму.', 'Матрица — компактная таблица-инструкция. Каждый её столбец показывает, куда правило отправляет один базисный вектор.', 'Пульт, преобразующий входные координаты в выходные.', 'A=[[1,2],[0,1]] отправляет x в Ax.', 'Матрица зависит от базиса и не равна самому абстрактному оператору.', 'vector-spaces'),
  t('dimension', 'Размерность', ['размерности', 'dim', 'dim V'], 'Число векторов в базисе, то есть число независимых направлений.', 'Размерность отвечает, сколько независимых ручек нужно, чтобы указать любой объект пространства.', 'Число независимых осей управления.', 'dim R³=3.', 'Размерность не равна числу всех векторов: их обычно бесконечно много.', 'vector-spaces', definition('definitions-module-3', 19)),
  t('subspace', 'Подпространство', ['подпространства', 'подпространству', 'линейное подпространство'], 'Часть пространства, закрытая для всех линейных комбинаций.', 'Это маленькая комната внутри большой, где сложение и растяжение никогда не выбрасывают нас наружу. Она обязательно содержит ноль.', 'Ровная дорожка через начало внутри площади.', 'Плоскость z=0 — подпространство R³.', 'Прямая, не проходящая через ноль, не подпространство.', 'vector-spaces', definition('definitions-module-3', 22)),
  t('map', 'Отображение', ['отображения', 'отображением', 'map'], 'Правило, назначающее каждому допустимому входу ровно один выход.', 'Это автомат: кладём один объект, а он по неизменному правилу выдаёт один объект. Разным входам разрешено давать одинаковый выход.', 'Автомат с одним результатом для каждого входа.', 'f(x)=x² отображает R в R.', 'Отображение не обязано быть линейным или обратимым.', 'operators'),
  t('function', 'Функция', ['функции', 'функцией', 'f(x)'], 'Отображение, обычно рассматриваемое для чисел или координат.', 'Функция — правило-автомат: каждому x выдаёт значение f(x). В алгебре слово «отображение» шире, но смысл тот же.', 'Машинка «вход → выход».', 'f(x)=2x+1.', 'Одному x нельзя назначать два разных значения.', 'operators'),
  t('linear-map', 'Линейное отображение', ['линейного отображения', 'линейная функция'], 'Отображение, сохраняющее сложение и умножение на скаляр.', 'Линейное правило не ломает рецепты из векторов: можно сначала сложить и растянуть, потом применить T, или сначала применить T к частям — выйдет одинаково.', 'Прозрачный автомат для линейных конструкций.', 'T(x,y)=(x+y,y).', 'Сдвиг T(x)=Ax+b при b≠0 не линейный.', 'operators', definition('definitions-module-4', 10)),
  t('kernel', 'Ядро', ['ядра', 'ядром', 'ker', 'ker T'], 'Все входы линейного отображения, которые переходят в ноль.', 'Ядро — набор вещей, которые автомат полностью стирает. Чем ядро больше, тем больше информации теряет отображение.', 'Корзина входов, ставших невидимыми.', 'Для T(x,y)=x ядро состоит из (0,y).', 'Ядро живёт во входном пространстве.', 'vector-spaces'),
  t('image', 'Образ', ['образа', 'образом', 'im', 'im T'], 'Все выходы, которые отображение действительно умеет получать.', 'Образ — полка достижимых результатов автомата. В выходном пространстве могут быть элементы, до которых он никогда не добирается.', 'Все товары, которые умеет выпускать машина.', 'Для T(x,y)=(x,0) образ — ось Ox.', 'Образ отображения — не картинка и не обязательно всё пространство значений.', 'vector-spaces'),
  t('rank', 'Ранг', ['ранга', 'ранг матрицы', 'rank'], 'Размерность образа или число независимых столбцов матрицы.', 'Ранг показывает, сколько независимых направлений сохранилось после работы матрицы.', 'Число реально работающих выходных каналов.', 'Матрица с одинаковыми ненулевыми столбцами имеет ранг 1.', 'Ранг не всегда равен числу строк или столбцов.', 'vector-spaces', definition('definitions-module-3', 23)),
  t('determinant', 'Определитель', ['определителя', 'определителем', 'det', 'det A'], 'Число, показывающее ориентированное изменение объёма матрицей.', 'Матрица растягивает или сжимает пространство. Модуль определителя говорит, во сколько раз изменился объём; ноль означает, что объём сплющился и обратного пути нет.', 'Коэффициент изменения площади или объёма.', 'det([[2,0],[0,3]])=6.', 'Определитель существует только у квадратной матрицы.', 'vector-spaces'),
  t('change-of-basis', 'Матрица перехода', ['матрицы перехода', 'смена базиса', 'переход между базисами'], 'Матрица, переводящая координаты между двумя базисами.', 'Она работает как словарь между двумя системами адресов одного пространства. Точка не двигается — меняется только её запись.', 'Перевод адреса с одной карты на другую.', 'Столбцы матрицы перехода часто состоят из координат новых базисных векторов в старом базисе.', 'Направление перехода зависит от соглашения; нельзя бездумно путать S и S⁻¹.', 'vector-spaces', definition('definitions-module-3', 20)),

  // Формы
  t('bilinear-form', 'Билинейная форма', ['билинейной формы', 'билинейная функция'], 'Правило, которое двум векторам ставит число и линейно по каждому аргументу.', 'Форма берёт две стрелки и измеряет их совместное взаимодействие. Если одну стрелку сложить из частей, результат тоже сложится из соответствующих измерений.', 'Измеритель взаимодействия двух векторов.', 'b(x,y)=xᵀAy.', 'Не всякая функция двух векторов билинейна.', 'forms', definition('definitions-module-4', 1)),
  t('quadratic-form', 'Квадратичная форма', ['квадратичной формы', 'q(x)', 'xᵀAx'], 'Однородное выражение второй степени q(x)=xᵀAx.', 'Она берёт один вектор и измеряет его «квадратическую энергию». В координатах появляются квадраты и попарные произведения, но нет линейных и постоянных слагаемых.', 'Чаша или седло, высота которого зависит от направления.', 'q(x,y)=x²+2xy+3y².', 'Выражение x²+y+1 не является квадратичной формой.', 'forms', definition('definitions-module-4', 2)),
  t('congruence', 'Конгруэнтность матриц', ['конгруэнтные матрицы', 'SᵀAS'], 'Связь A′=SᵀAS, возникающая при смене координат формы.', 'Форма принимает два одинаково преобразованных аргумента, поэтому матрица смены базиса появляется с обеих сторон.', 'Одна мерка, переписанная на новых осях.', 'При x=Sx′ форма xᵀAx получает матрицу A′=SᵀAS.', 'Это не подобие S⁻¹AS для операторов.', 'forms'),
  t('positive-definite', 'Положительная определённость', ['положительно определена', 'положительно определённая форма'], 'Условие q(x)>0 для каждого ненулевого x.', 'Куда ни шагни от нуля, значение формы становится положительным: поверхность похожа на чашу с единственным дном в нуле.', 'Чаша, растущая во всех направлениях.', 'x²+y² положительно определена.', 'Неотрицательность допускает ненулевые x с q(x)=0 и потому слабее.', 'forms', definition('definitions-module-4', 3)),
  t('indefinite-form', 'Знакопеременная форма', ['знакопеременной формы', 'неопределённая форма'], 'Квадратичная форма, принимающая и положительные, и отрицательные значения.', 'В одних направлениях значение поднимается выше нуля, в других падает ниже — поверхность похожа на седло.', 'Седло с подъёмом и спуском.', 'x²−y²: на (1,0) плюс, на (0,1) минус.', 'Одного нулевого значения недостаточно для знакопеременности.', 'forms', definition('definitions-module-4', 4)),
  t('canonical-form', 'Канонический вид', ['канонического вида', 'диагональный вид формы'], 'Запись квадратичной формы без смешанных произведений координат.', 'Мы поворачиваем или заменяем оси так, чтобы каждое новое направление имело отдельный квадрат и не смешивалось с соседями.', 'Развязать спутанные пружины на независимые.', 'q=2y₁²−3y₂².', 'Канонический вид может иметь коэффициенты, отличные от ±1.', 'forms', definition('definitions-module-4', 5)),
  t('inertia-index', 'Индексы инерции', ['индексов инерции', 'положительный индекс инерции', 'отрицательный индекс инерции'], 'Числа положительных и отрицательных квадратов в нормальном виде формы.', 'После распутывания формы считаем направления-чаши и направления-перевёрнутые чаши. Эти количества не зависят от разумной смены координат.', 'Постоянный счёт плюсов и минусов.', 'Для x²+y²−z² индексы равны (2,1).', 'Ранг — сумма ненулевых индексов, но не один из них.', 'forms', definition('definitions-module-4', 9)),
  t('sylvester-criterion', 'Критерий Сильвестра', ['критерия Сильвестра', 'угловые миноры'], 'Проверка определённости симметричной матрицы по ведущим главным минорам.', 'Вместо проверки бесконечного числа векторов вычисляем несколько определителей верхних левых квадратов. Все положительны — форма положительно определена.', 'Серия контрольных лампочек матрицы.', 'Для [[2,1],[1,2]] миноры 2 и 3 положительны.', 'Нужны ведущие угловые миноры, а не произвольные.', 'forms', definition('definitions-module-4', 8)),
  t('lagrange-method', 'Метод Лагранжа', ['метода Лагранжа', 'выделение полных квадратов'], 'Алгоритм приведения квадратичной формы к диагональному виду выделением квадратов.', 'Мы собираем смешанные кусочки в полный квадрат, как в школьной формуле (x+y)², и повторяем с остатком, пока связи между переменными не исчезнут.', 'Распутывание узлов по одному.', 'x²+2xy=(x+y)²−y².', 'Это не метод множителей Лагранжа из оптимизации.', 'forms'),

  // Операторы и спектр
  t('linear-operator', 'Линейный оператор', ['линейного оператора', 'оператор T'], 'Линейное отображение пространства в само себя.', 'Это линейный автомат, у которого вход и выход одного типа, поэтому его можно применять снова и снова.', 'Машина, возвращающая детали на ту же ленту.', 'Поворот плоскости — линейный оператор R²→R².', 'Отображение V→W при V≠W обычно называют отображением, а не оператором.', 'operators'),
  t('similar-matrices', 'Подобные матрицы', ['подобия матриц', 'S⁻¹AS'], 'Матрицы одного оператора в разных базисах: A′=S⁻¹AS.', 'Сам автомат не изменился; мы лишь описали его на другой координатной карте. Поэтому важные свойства вроде спектра сохраняются.', 'Одна машина с инструкциями на разных языках.', 'A и S⁻¹AS подобны.', 'Подобие не равно конгруэнтности SᵀAS.', 'operators'),
  t('eigenvector', 'Собственный вектор', ['собственного вектора', 'собственные векторы', 'eigenvector'], 'Ненулевой вектор, направление которого оператор не меняет.', 'Оператор может растянуть, сжать или развернуть этот вектор, но не увести его с собственной прямой.', 'Стрелка, скользящая только вдоль своей рельсы.', 'Для diag(2,3) вектор (1,0) собственный.', 'Нулевой вектор собственным не считают.', 'operators', definition('definitions-module-4', 14)),
  t('eigenvalue', 'Собственное значение', ['собственного значения', 'собственные значения', 'eigenvalue', 'λ'], 'Коэффициент растяжения собственного вектора: Tv=λv.', 'Это число сообщает, что оператор сделал с особым направлением: растянул, сжал, развернул или обнулил.', 'Метка масштаба на собственной рельсе.', 'Для diag(2,3) значение 2 соответствует оси Ox.', 'Собственное значение относится к оператору, а не к произвольному вектору.', 'operators', definition('definitions-module-4', 14)),
  t('characteristic-polynomial', 'Характеристический многочлен', ['характеристического многочлена', 'χ_A', 'det(A−λI)'], 'Многочлен, корни которого являются собственными значениями.', 'Мы вычитаем из матрицы неизвестное растяжение λ и спрашиваем, когда получившаяся матрица сплющивает направление. Ответ кодирует один многочлен.', 'Детектор особых масштабов.', 'χ_A(λ)=det(A−λI).', 'Знак может зависеть от соглашения det(A−λI) или det(λI−A), но корни одинаковы.', 'operators', definition('definitions-module-4', 15)),
  t('spectrum', 'Спектр', ['спектра', 'спектром', 'spec T'], 'Множество собственных значений оператора.', 'Это список всех специальных масштабов, с которыми оператор действует на собственные направления.', 'Палитра допустимых растяжений.', 'Спектр diag(2,3) равен {2,3}.', 'Спектр — не набор собственных векторов.', 'operators', definition('definitions-module-4', 16)),
  t('eigenspace', 'Собственное подпространство', ['собственного подпространства', 'E_λ'], 'Ядро T−λI: все собственные векторы значения λ вместе с нулём.', 'Собираем все направления, которые оператор растягивает одинаково в λ раз. Вместе они образуют целую линейную комнату.', 'Команда векторов с одним режимом работы.', 'E₂ для diag(2,3) — ось Ox.', 'Ноль входит в подпространство, хотя сам не собственный вектор.', 'operators', definition('definitions-module-4', 17)),
  t('multiplicity', 'Кратность собственного значения', ['алгебраическая кратность', 'геометрическая кратность', 'кратности λ'], 'Алгебраическая кратность считает корень многочлена, геометрическая — размерность собственного подпространства.', 'Один счётчик смотрит, сколько раз λ записалось в характеристическом многочлене, другой — сколько независимых собственных направлений реально нашлось.', 'Паспортное и фактическое число мест.', 'Всегда 1≤geom(λ)≤alg(λ).', 'Две кратности могут не совпадать.', 'operators', definition('definitions-module-4', 18)),
  t('diagonalizable', 'Диагонализируемость', ['диагонализируем', 'диагональная матрица оператора'], 'Существование базиса из собственных векторов.', 'Если собственных направлений хватает на весь базис, оператор можно описать очень просто: он отдельно растягивает каждую координатную ось.', 'Настроить машину на независимые ползунки.', 'Матрица с n различными собственными значениями диагонализируема.', 'Наличие хотя бы одного собственного вектора недостаточно.', 'operators', definition('definitions-module-4', 21)),
  t('trace', 'След матрицы', ['следа матрицы', 'tr', 'tr A'], 'Сумма диагональных элементов квадратной матрицы.', 'След — быстрый числовой отпечаток оператора. Над полем разложения он равен сумме собственных значений с кратностями.', 'Сумма показаний главной диагонали.', 'tr([[2,1],[0,3]])=5.', 'След не равен определителю.', 'operators'),

  // Евклидова геометрия
  t('inner-product', 'Скалярное произведение', ['скалярного произведения', '⟨x,y⟩', 'dot product'], 'Число, измеряющее совместное направление и длины двух векторов.', 'Оно говорит, насколько две стрелки смотрят в одну сторону. Положительное — скорее вместе, ноль — под прямым углом, отрицательное — скорее навстречу.', 'Измеритель согласованности направлений.', 'В R²: ⟨(1,2),(3,4)⟩=11.', 'Произведение векторов не является обычным покоординатным умножением с векторным ответом.', 'euclidean', definition('definitions-module-4', 22)),
  t('euclidean-space', 'Евклидово пространство', ['евклидова пространства', 'евклидово V'], 'Вещественное векторное пространство со скалярным произведением.', 'Это векторное пространство, которому добавили линейку и угломер: теперь можно измерять длины, углы и расстояния.', 'Комната с координатами, линейкой и транспортиром.', 'Rⁿ со стандартным скалярным произведением.', 'Одного векторного пространства недостаточно для понятия угла.', 'euclidean', definition('definitions-module-4', 22)),
  t('norm', 'Норма', ['нормы', 'нормой', 'длина вектора', '||x||'], 'Длина вектора: ||x||=√⟨x,x⟩.', 'Норма забывает направление и оставляет только размер стрелки.', 'Длина стрелки по линейке.', '||(3,4)||=5.', 'Норма всегда неотрицательна и равна нулю только для нулевого вектора.', 'euclidean'),
  t('orthogonal', 'Ортогональность', ['ортогональны', 'ортогонального', 'x ⟂ y'], 'Условие ⟨x,y⟩=0.', 'Два ненулевых вектора ортогональны, если стоят под прямым углом и совсем не имеют общей направленной составляющей.', 'Перпендикулярные стрелки.', '(1,0)⊥(0,1).', 'Нулевой вектор ортогонален всем, хотя у него нет геометрического направления.', 'euclidean'),
  t('orthonormal-basis', 'Ортонормированный базис', ['ортонормированного базиса', 'ОНБ'], 'Базис из попарно ортогональных единичных векторов.', 'Это набор координатных линеек одинаковой длины, стоящих под прямыми углами. В нём формулы для длины и проекции особенно просты.', 'Идеально выровненные единичные оси.', 'Стандартный базис Rⁿ ортонормирован.', 'Ортогональный базис может состоять из векторов не единичной длины.', 'euclidean', definition('definitions-module-4', 24)),
  t('gram-matrix', 'Матрица Грама', ['матрицы Грама', 'матрицей Грама', 'Gram', 'G'], 'Матрица всех попарных скалярных произведений выбранных векторов.', 'Это таблица знакомств: ячейка ij показывает, насколько i-я и j-я стрелки направлены вместе. Диагональ хранит квадраты длин.', 'Таблица взаимных углов и длин.', 'G_ij=⟨v_i,v_j⟩.', 'Матрица Грама зависит и от векторов, и от скалярного произведения.', 'euclidean', definition('definitions-module-4', 25)),
  t('gram-schmidt', 'Процесс Грама—Шмидта', ['ортогонализация Грама—Шмидта', 'Gram-Schmidt'], 'Алгоритм превращения независимой системы в ортогональную с той же оболочкой.', 'Берём следующую стрелку и вычитаем из неё все тени на уже выбранные направления. Остаётся новая стрелка, перпендикулярная предыдущим.', 'Расправить спутанные оси по очереди.', 'u₂=v₂−proj_{u₁}v₂.', 'Если исходные векторы зависимы, на одном шаге получится ноль.', 'euclidean'),
  t('orthogonal-complement', 'Ортогональное дополнение', ['ортогонального дополнения', 'U⊥'], 'Все векторы, перпендикулярные каждому вектору подпространства U.', 'Это все направления, которые ни капли не смотрят вдоль U.', 'Направления строго поперёк комнаты U.', 'Для плоскости xy в R³ дополнение — ось Oz.', 'Это не множество векторов, просто не лежащих в U.', 'euclidean', definition('definitions-module-4', 30)),
  t('projection', 'Ортогональная проекция', ['ортогональной проекции', 'проекция на подпространство', 'proj'], 'Ближайшая к вектору точка подпространства, полученная перпендикулярным опусканием.', 'Посвети на стрелку строго перпендикулярным светом: её тень на подпространстве и есть проекция. Остаток направлен поперёк подпространства.', 'Тень на ровной стене.', 'proj_u x=(⟨x,u⟩/⟨u,u⟩)u.', 'Косая проекция может быть линейной, но не ортогональной.', 'euclidean', definition('definitions-module-4', 31)),
  t('cauchy-schwarz', 'Неравенство Коши—Буняковского', ['Коши-Буняковского', 'Cauchy-Schwarz'], 'Оценка |⟨x,y⟩|≤||x||·||y||.', 'Совместное направление двух стрелок не может быть сильнее произведения их длин. Равенство бывает, когда они лежат на одной прямой.', 'Предел возможного совпадения направлений.', '|x·y|≤||x||||y||.', 'Это не формула равенства для любых векторов.', 'euclidean', definition('definitions-module-4', 23)),
  t('affine-subspace', 'Линейное многообразие', ['линейного многообразия', 'аффинное подпространство'], 'Сдвинутое подпространство L=a+U.', 'Берём линейную комнату через ноль и целиком переносим её в другое место. Форма сохраняется, но ноль может больше не лежать внутри.', 'Параллельно перенесённая прямая или плоскость.', '{(x,y): y=1} — линейное многообразие.', 'Если оно не проходит через ноль, это не линейное подпространство.', 'euclidean', definition('definitions-module-4', 33)),

  // Специальные операторы
  t('adjoint-operator', 'Сопряжённый оператор', ['сопряженного оператора', 'T*', 'adjoint'], 'Оператор T*, переносящий действие T между аргументами скалярного произведения.', 'T* — партнёр T, выбранный так, чтобы ⟨Tx,y⟩ всегда равнялось ⟨x,T*y⟩. Он показывает, как действие должно перейти на другую сторону измерения.', 'Перенос действия через знак скалярного произведения.', 'В ОНБ матрица T* равна Aᵀ над R.', 'В произвольном базисе это не просто транспонирование.', 'orthogonal-operators', definition('definitions-module-4', 36)),
  t('self-adjoint', 'Самосопряжённый оператор', ['самосопряженного оператора', 'симметрический оператор', 'T=T*'], 'Оператор, совпадающий со своим сопряжённым.', 'Такой оператор одинаково ведёт себя с обеих сторон скалярного произведения. У него вещественные собственные значения и можно выбрать ортонормированный базис собственных векторов.', 'Идеально симметричный измерительный автомат.', 'В ОНБ вещественная симметричная матрица задаёт самосопряжённый оператор.', 'Симметричность матрицы без уточнения базиса может ввести в заблуждение.', 'orthogonal-operators', definition('definitions-module-4', 37)),
  t('orthogonal-matrix', 'Ортогональная матрица', ['ортогональной матрицы', 'QᵀQ=I'], 'Матрица Q, для которой QᵀQ=I.', 'Её столбцы образуют ортонормированный базис. Она не растягивает пространство, а только поворачивает или отражает.', 'Жёсткое движение без деформации.', 'Матрица поворота плоскости ортогональна.', 'Ортогональная матрица не означает, что все её элементы взаимно перпендикулярны.', 'orthogonal-operators', definition('definitions-module-4', 42)),
  t('orthogonal-operator', 'Ортогональный оператор', ['ортогонального оператора', 'изометрический оператор'], 'Линейный оператор, сохраняющий скалярное произведение и длины.', 'Он двигает всё пространство как твёрдый лист: расстояния и углы не меняются, разрешены повороты и отражения.', 'Поворот или отражение прозрачной плёнки.', 'T(x,y)=(-y,x) — поворот на 90°.', 'Сдвиг сохраняет расстояния, но не является линейным ортогональным оператором.', 'orthogonal-operators', definition('definitions-module-4', 43)),
  t('spectral-theorem', 'Спектральная теорема', ['спектральной теоремы', 'спектральное разложение'], 'Самосопряжённый оператор диагонализируется в ортонормированном базисе.', 'Для симметричного измерительного автомата всегда найдутся взаимно перпендикулярные главные направления, вдоль которых он только растягивает.', 'Найти естественные оси деформации.', 'A=QΛQᵀ для вещественной симметричной A.', 'Для произвольной вещественной матрицы утверждение неверно.', 'orthogonal-operators', definition('definitions-module-4', 47)),
  t('rotation', 'Поворот', ['поворота', 'матрица поворота'], 'Ортогональное преобразование, сохраняющее ориентацию.', 'Все стрелки разворачиваются на согласованный угол, но их длины и углы между ними остаются прежними.', 'Повернуть лист бумаги вокруг центра.', 'В R² Rθ=[[cosθ,−sinθ],[sinθ,cosθ]].', 'Поворот не является сдвигом.', 'orthogonal-operators'),
  t('reflection', 'Отражение', ['отражения', 'зеркальное отражение'], 'Ортогональное преобразование, меняющее ориентацию.', 'Это зеркальное переворачивание пространства относительно прямой или плоскости: длины сохраняются, но «лево» и «право» меняются местами.', 'Отражение в зеркале.', 'diag(1,−1) отражает плоскость относительно Ox.', 'Отражение обычно имеет det=−1, а не +1.', 'orthogonal-operators'),

  // Разложения
  t('matrix-decomposition', 'Разложение матрицы', ['матричное разложение', 'факторизация матрицы'], 'Представление сложной матрицы произведением более простых матриц.', 'Мы разбираем сложную машину на несколько понятных блоков: поворот, растяжение, отражение или треугольное действие.', 'Разобрать устройство на простые модули.', 'A=QR или A=UΣVᵀ.', 'Это не разложение матрицы на сумму её строк.', 'decompositions'),
  t('qr-decomposition', 'QR-разложение', ['QR', 'QR decomposition'], 'Представление A=QR, где Q имеет ортонормированные столбцы, а R верхнетреугольна.', 'Сначала выбираем аккуратно перпендикулярные направления Q, затем R хранит, как из них собрать исходные столбцы.', 'Выпрямить каркас и записать размеры деталей.', 'Получается из процесса Грама—Шмидта.', 'Для прямоугольных матриц размеры Q и R зависят от полной или экономной версии.', 'decompositions', definition('definitions-module-4', 49)),
  t('svd', 'Сингулярное разложение', ['SVD', 'сингулярного разложения', 'UΣVᵀ'], 'Представление A=UΣVᵀ: поворот, растяжение по осям и ещё поворот.', 'Любая матрица сначала выбирает удобные входные оси, затем растягивает каждую отдельно на неотрицательное число, затем поворачивает результат.', 'Повернуть пластилин, растянуть по осям, снова повернуть.', 'A=UΣVᵀ, диагональ Σ содержит сингулярные числа.', 'SVD существует и для прямоугольной матрицы; это не обычная диагонализация A.', 'decompositions', definition('definitions-module-4', 50)),
  t('singular-value', 'Сингулярное число', ['сингулярного числа', 'сингулярные значения', 'σ'], 'Неотрицательный коэффициент растяжения в SVD.', 'Это длина главного растяжения матрицы. Большое σ усиливает направление, нулевое полностью сплющивает его.', 'Настройка отдельного ползунка масштаба.', 'σ_i=√λ_i(AᵀA).', 'Сингулярные числа всегда неотрицательны и не равны в общем случае собственным значениям A.', 'decompositions'),
  t('polar-decomposition', 'Полярное разложение', ['полярного разложения', 'A=QS'], 'Представление оператора как ортогонального движения и неотрицательного самосопряжённого растяжения.', 'Матрица сначала деформирует фигуру вдоль перпендикулярных осей, а потом жёстко поворачивает или отражает её.', 'Растянуть резину, затем повернуть.', 'A=QS, где S=√(AᵀA).', 'Это не полярные координаты точки.', 'decompositions', definition('definitions-module-4', 51)),
  t('upper-triangular', 'Верхнетреугольная матрица', ['верхнетреугольной матрицы', 'треугольная матрица'], 'Квадратная матрица с нулями ниже главной диагонали.', 'Все заполненные клетки находятся на диагонали или выше неё, поэтому системы с такой матрицей удобно решать с конца.', 'Лестница чисел в верхнем углу.', '[[1,2],[0,3]] — верхнетреугольная.', 'Диагональная матрица — частный случай треугольной.', 'decompositions'),

  // Кривые, поверхности и двойственность
  t('conic', 'Кривая второго порядка', ['кривой второго порядка', 'коника', 'коническое сечение'], 'Множество точек плоскости, заданное квадратным уравнением.', 'Это рисунок, который получается из уравнения с x², xy, y² и более простыми членами. После поворота и сдвига осей он узнаётся как эллипс, гипербола, парабола или вырожденный случай.', 'След от разреза конуса плоскостью.', 'x²/4+y²=1 — эллипс.', 'Не каждое квадратное уравнение даёт непустую гладкую кривую.', 'geometry-dual'),
  t('ellipse', 'Эллипс', ['эллипса', 'эллипсом'], 'Точки, сумма расстояний до двух фокусов которых постоянна.', 'У эллипса две особые точки-фокуса. Где бы мы ни стояли на границе, путь до первого фокуса плюс путь до второго один и тот же.', 'Растянутая окружность с правилом двух гвоздей и нити.', 'x²/a²+y²/b²=1, a≥b>0.', 'Эллипс не имеет ветвей, уходящих в бесконечность.', 'geometry-dual', definition('definitions-exam', 3)),
  t('hyperbola', 'Гипербола', ['гиперболы', 'гиперболой'], 'Точки, модуль разности расстояний до двух фокусов которых постоянен.', 'У неё две отдельные ветви. Разница путей до двух фокусов остаётся одной и той же.', 'Два расходящихся крыла.', 'x²/a²−y²/b²=1.', 'Гипербола — не парабола и состоит из двух ветвей.', 'geometry-dual', definition('definitions-exam', 4)),
  t('parabola', 'Парабола', ['параболы', 'параболой'], 'Точки, равноудалённые от фокуса и директрисы.', 'Каждая точка параболы одинаково далеко от одной особой точки и одной прямой. Поэтому получается одна открытая ветвь.', 'След брошенного мяча или чашеобразная антенна.', 'y²=2px.', 'Парабола не является половиной эллипса.', 'geometry-dual', definition('definitions-exam', 5)),
  t('focus', 'Фокус', ['фокуса', 'фокусами', 'фокусы'], 'Особая точка, через расстояния до которой определяется коника.', 'Фокус — закреплённый маячок. Эллипс и гипербола сравнивают пути до двух маячков, парабола — путь до маячка и до прямой.', 'Маяк для измерения расстояний.', 'У параболы y²=2px фокус (p/2,0) при таком соглашении.', 'Фокус обычно не лежит на самой кривой.', 'geometry-dual'),
  t('eccentricity', 'Эксцентриситет', ['эксцентриситета', 'эксцентриситетом'], 'Безразмерное число, показывающее форму и тип коники.', 'Оно измеряет, насколько кривая отличается от окружности: для эллипса меньше 1, для параболы равно 1, для гиперболы больше 1.', 'Регулятор вытянутости коники.', 'У окружности e=0.', 'Это не расстояние и потому не имеет единиц длины.', 'geometry-dual'),
  t('quadric', 'Поверхность второго порядка', ['поверхности второго порядка', 'квадрика'], 'Множество точек пространства, заданное квадратным уравнением трёх координат.', 'Это трёхмерная родственница коник: уравнение с x²,y²,z² может описать яйцо-эллипсоид, седло, чашу, цилиндр или гиперболоид.', 'Трёхмерная фигура из квадратного уравнения.', 'x²+y²+z²=1 — сфера.', 'Не всякая квадрика замкнута или непуста.', 'geometry-dual'),
  t('cylinder-surface', 'Цилиндрическая поверхность', ['цилиндрической поверхности', 'цилиндр второго порядка'], 'Поверхность, составленная из параллельных прямых через точки направляющей кривой.', 'Берём плоскую кривую и через каждую её точку проводим одинаково направленную бесконечную прямую. Получается поверхность, не меняющаяся вдоль этого направления.', 'Протянуть рисунок бесконечно вверх и вниз.', 'x²+y²=1 не зависит от z и задаёт круговой цилиндр.', 'Цилиндрическая поверхность не обязана быть круглой.', 'geometry-dual', definition('definitions-exam', 7)),
  t('ruled-surface', 'Линейчатая поверхность', ['линейчатой поверхности', 'линейчатые поверхности'], 'Поверхность, через каждую точку которой проходит лежащая на ней прямая.', 'Поверхность как будто соткана из прямых нитей. Нити могут быть не параллельны, поэтому не всякая линейчатая поверхность — цилиндр.', 'Ткань из прямых спиц.', 'Однополостный гиперболоид и гиперболический параболоид линейчаты.', 'Линейчатая не означает плоская.', 'geometry-dual', definition('definitions-exam', 8)),
  t('functional', 'Линейный функционал', ['линейного функционала', 'функционал f'], 'Линейное отображение из векторного пространства в поле скаляров.', 'Функционал берёт целый вектор и выдаёт одно число, сохраняя сложение и растяжение. Его можно понимать как измерительный датчик.', 'Датчик, превращающий стрелку в одно показание.', 'f(x,y)=2x−y.', 'Функционал выдаёт скаляр, а не новый вектор того же пространства.', 'geometry-dual', definition('definitions-exam', 12)),
  t('dual-space', 'Сопряжённое пространство', ['двойственное пространство', 'V*', 'пространство функционалов'], 'Векторное пространство всех линейных функционалов на V.', 'Если V — мир векторов, то V* — мир всех возможных линейных измерительных приборов для этих векторов.', 'Ящик со всеми линейными датчиками.', '(Rⁿ)* состоит из линейных правил x↦aᵀx.', 'V* не является множеством сопряжённых операторов.', 'geometry-dual', definition('definitions-exam', 13)),
  t('covector', 'Ковектор', ['ковектора', 'ковектором', 'covector'], 'Элемент двойственного пространства, то есть линейный функционал.', 'Вектор задаёт направление или состояние, а ковектор — способ снять с него одно линейное показание. Координаты ковектора меняются так, чтобы само число измерения оставалось прежним.', 'Линейка-датчик вместо стрелки.', 'Строка [2,−1] задаёт f(x,y)=2x−y.', 'Ковектор нельзя без выбранного скалярного произведения автоматически считать обычным вектором.', 'geometry-dual'),
  t('dual-basis', 'Двойственный базис', ['взаимные базисы', 'двойственного базиса', 'εⁱ'], 'Базис функционалов, каждый из которых считывает одну координату исходного базиса.', 'Для каждой координатной ручки создаём отдельный датчик: он показывает 1 на своей ручке и 0 на всех остальных.', 'Набор датчиков по одному на каждую ось.', 'εⁱ(e_j)=δⁱ_j.', 'Двойственный базис живёт в V*, а не в V.', 'geometry-dual', definition('definitions-exam', 15)),
  t('kronecker-delta', 'Символ Кронекера', ['дельта Кронекера', 'δᵢⱼ'], 'Число δᵢⱼ, равное 1 при i=j и 0 иначе.', 'Это маленький переключатель: сравнивает два номера и включает единицу только когда они совпали.', 'Лампочка совпадения индексов.', 'δ₂₂=1, δ₁₂=0.', 'Это не переменная, принимающая произвольные значения.', 'geometry-dual'),
  t('riesz-isomorphism', 'Изоморфизм Рисса', ['изоморфизма Рисса', 'отождествление V и V*'], 'Соответствие v↦⟨·,v⟩ между конечномерным евклидовым пространством и его двойственным.', 'Скалярное произведение превращает каждую стрелку v в датчик: датчик подставляет x и измеряет, насколько x направлен вдоль v.', 'Сделать из направления измерительную линейку.', 'J(v)(x)=⟨x,v⟩.', 'Соответствие зависит от скалярного произведения и не является естественным без него.', 'geometry-dual', definition('definitions-exam', 16)),
];

const normalizeExample = (item) => typeof item === 'string' ? { text: item } : item;

export const glossary = glossaryBase.map((entry) => {
  const enrichment = glossaryEnrichment[entry.id] ?? {};
  return {
    ...entry,
    ...enrichment,
    aliases: [...new Set([...entry.aliases, ...(enrichment.aliases ?? [])])],
    perspectives: enrichment.perspectives ?? [],
    analogies: enrichment.analogies ?? [entry.analogy],
    examples: (enrichment.examples ?? [entry.example]).map(normalizeExample),
    related: enrichment.related ?? [],
  };
});

export const glossaryById = Object.fromEntries(glossary.map((entry) => [entry.id, entry]));

if (Object.keys(glossaryById).length !== glossary.length) {
  throw new Error('Glossary contains duplicate ids');
}

const normalizedAliasOwners = new Map();
for (const entry of glossary) {
  for (const alias of [entry.term, ...entry.aliases]) {
    const normalized = alias.trim().toLocaleLowerCase('ru-RU');
    const owner = normalizedAliasOwners.get(normalized);
    if (owner && owner !== entry.id) {
      throw new Error(`Glossary alias "${alias}" belongs to both ${owner} and ${entry.id}`);
    }
    normalizedAliasOwners.set(normalized, entry.id);
  }
}

export const glossaryAliases = [...normalizedAliasOwners.entries()]
  .map(([alias, id]) => ({ alias, id }))
  .sort((a, b) => b.alias.length - a.alias.length || a.alias.localeCompare(b.alias, 'ru'));

// Односимвольные обозначения вроде 0, 1 и σ полезны для поиска, но не должны
// превращать каждую формулу в россыпь вложенных кнопок-подсказок.
export const glossaryProseAliases = glossaryAliases.filter(({ alias }) => (alias.match(/\p{L}/gu) ?? []).length >= 2);

const requiredFields = ['id', 'term', 'aliases', 'short', 'child', 'analogies', 'examples', 'perspectives', 'related', 'notThis', 'topicId', 'definitionLink'];
const topicCounts = glossary.reduce((counts, entry) => ({
  ...counts,
  [entry.topicId]: (counts[entry.topicId] ?? 0) + 1,
}), {});
const invalidEntries = glossary
  .filter((entry) => requiredFields.some((field) => entry[field] === undefined || entry[field] === '' || (Array.isArray(entry[field]) && field !== 'perspectives' && field !== 'related' && entry[field].length === 0)))
  .map((entry) => entry.id);

export const enrichedGlossaryIds = Object.keys(glossaryEnrichment);

export const glossaryCoverage = {
  total: glossary.length,
  aliases: glossaryAliases.length,
  topicCounts,
  definitionLinks: glossary.filter((entry) => entry.definitionLink).length,
  invalidEntries,
  complete: glossary.length >= 80 && invalidEntries.length === 0,
};

if (!glossaryCoverage.complete) {
  throw new Error(`Incomplete glossary: ${invalidEntries.join(', ') || `${glossary.length}/80 terms`}`);
}
